export interface ReelRequest {
  /**
     * What to highlight, e.g. "the fact about faith"
     * @minLength 3
     */
  prompt: string;
  /**
     * Restrict the reel to one asset, or null/omitted for the whole library
     * @nullable
     */
  media_id?: string | null;
  /**
     * Restrict the reel to a set of assets (e.g. a project's media pool)
     * @nullable
     */
  media_ids?: string[] | null;
  /** @nullable */
  project_id?: string | null;
  /**
     * Desired run time in seconds; the builder selects enough material to reach it (up to 4 hours)
     * @minimum 30
     * @maximum 14400
     * @nullable
     */
  target_duration_seconds?: number | null;
  preset?: ReelRequestPreset;
  burn_captions?: boolean;
  /**
     * Clip cap when no target duration is given
     * @minimum 1
     * @maximum 500
     */
  max_clips?: number;
}

export interface ReelClip {
  media_id: string;
  filename: string;
  start_time: number;
  end_time: number;
  /**
     * Transcript text that matched the prompt
     * @nullable
     */
  snippet?: string | null;
  /**
     * Preview frame near the clip start (relative thumbnail path)
     * @nullable
     */
  thumbnail_url?: string | null;
}

export interface ReelJob {
  id: string;
  prompt: string;
  /**
     * Set when the reel is scoped to one asset
     * @nullable
     */
  media_id?: string | null;
  /** @nullable */
  project_id?: string | null;
  /**
     * Requested run time in seconds, when one was given
     * @nullable
     */
  target_duration_seconds?: number | null;
  /** original | vertical */
  preset: string;
  burn_captions: boolean;
  clips: ReelClip[];
  /** pending | running | success | error */
  status: string;
  progress: number;
  /**
     * Set when status is success
     * @nullable
     */
  output_url?: string | null;
  /** @nullable */
  error_message?: string | null;
  created_at: string;
  /** @nullable */
  finished_at?: string | null;
}

/**
 * Cut for one platform, or null/omitted for all scored platforms
 * @nullable
 */
export type SocialCutsRequestPlatform = typeof SocialCutsRequestPlatform[keyof typeof SocialCutsRequestPlatform] | null;


export const SocialCutsRequestPlatform = {
  youtube: 'youtube',
  instagram: 'instagram',
  x: 'x',
  facebook: 'facebook',
  tiktok: 'tiktok',
} as const;

export interface SocialCutsRequest {
  /**
     * Cut for one platform, or null/omitted for all scored platforms
     * @nullable
     */
  platform?: SocialCutsRequestPlatform;
}

export interface ClipExportInput {
  /** edl | csv | json | fcpxml | otio */
  format: string;
}

export interface TightenInput {
  /** Minimum gap between speech segments (seconds) to cut, default 1.25 */
  silence_threshold?: number;
  /** Also cut segments that are only filler words, default true */
  remove_fillers?: boolean;
}

export interface TightenCut {
  start: number;
  end: number;
  /** silence | filler */
  reason: string;
}

export interface TightenResult {
  media_id: string;
  /** Clip list containing the kept segments, ready for export or rough cut */
  clip_list_id: string;
  kept_segments: number;
  cuts: TightenCut[];
  removed_seconds: number;
  original_duration: number;
}

export interface RoughCutInput {
  /** original | vertical, default original */
  preset?: string;
  /** Burn subtitles into the video, default false */
  burn_captions?: boolean;
}

export interface StoryRequestIn {
  /** @minItems 1 */
  asset_ids: string[];
  /**
     * Optional editorial direction for the storyline
     * @nullable
     */
  prompt?: string | null;
  /** @nullable */
  project_id?: string | null;
}

export interface StoryJob {
  id: string;
  /** @nullable */
  prompt?: string | null;
  /** @nullable */
  project_id?: string | null;
  asset_ids: string[];
  /** pending | running | success | error */
  status: string;
  progress: number;
  /** @nullable */
  title?: string | null;
  /** @nullable */
  narrative?: string | null;
  /**
     * Clip list with the ordered cross-asset clips
     * @nullable
     */
  clip_list_id?: string | null;
  /** @nullable */
  error_message?: string | null;
  created_at: string;
  /** @nullable */
  finished_at?: string | null;
}

export interface ClipExportResult {
  format: string;
  content: string;
  filename?: string;
}

export type ListMediaParams = {
status?: string;
/**
 * Case-insensitive match on filename, title, or source path
 */
search?: string;
sort?: ListMediaSort;
limit?: number;
offset?: number;
};

export type ListMediaSort = typeof ListMediaSort[keyof typeof ListMediaSort];


export const ListMediaSort = {
  created_desc: 'created_desc',
  created_asc: 'created_asc',
  name_asc: 'name_asc',
  name_desc: 'name_desc',
  duration_desc: 'duration_desc',
  duration_asc: 'duration_asc',
  size_desc: 'size_desc',
  size_asc: 'size_asc',
} as const;

export type GetMediaTranscriptParams = {
/**
 * ISO language code — return translated text where available
 */
lang?: string;
};

export type GetCaptionsParams = {
format: GetCaptionsFormat;
/**
 * Translation language code, omit for original
 */
lang?: string;
};

export type GetCaptionsFormat = typeof GetCaptionsFormat[keyof typeof GetCaptionsFormat];


export const GetCaptionsFormat = {
  srt: 'srt',
  vtt: 'vtt',
} as const;

export type ListPeopleParams = {
/**
 * @minimum 1
 * @maximum 200
 */
limit?: number;
/**
 * @minimum 0
 */
offset?: number;
};

export type ListJobsParams = {
media_id?: string;
status?: string;
limit?: number;
};

export type ListClipListsParams = {
/**
 * Only clip lists linked to this project
 */
project_id?: string;
};

export type ListRendersParams = {
clip_list_id?: string;
/**
 * Only renders of this asset
 */
media_id?: string;
/**
 * Only renders linked to this project
 */
project_id?: string;
limit?: number;
};

export type ListReelsParams = {
limit?: number;
/**
 * Only reels scoped to this asset
 */
media_id?: string;
/**
 * Only reels linked to this project
 */
project_id?: string;
};

export type ListStoriesParams = {
/**
 * Only stories linked to this project
 */
project_id?: string;
};

